    public void validateUserWithMultipleViolations() {
        // Precondition 1: User data with empty name, invalid email, high age, and disabled account
        User user = new User("", "invalid-email", 250, false);

        // Precondition 2: System setup with rules for name, email, age, and account status
        Validator<User> validator = ValidatorBuilder.<User>of()
                .constraint(User::getName, "name", c -> c.notNull()
                        .greaterThanOrEqual(1)
                        .lessThanOrEqual(100))
                .constraint(User::getEmail, "email", c -> c.notNull()
                        .email())
                .constraint(User::getAge, "age", c -> c.notNull()
                        .lessThanOrEqual(200))
                .constraint(User::isEnabled, "enabled", c -> c.isTrue())
                .build();

        // Precondition 3: System runs validation
        ConstraintViolations violations = validator.validate(user);

        // Expected Result 1: System correctly says the user data is invalid
        assertThat(violations.isValid()).isFalse();

        // Expected Result 2: Four issues are reported
        List<ViolationDetail> details = violations.details();
        assertThat(details).hasSize(4);

        // Issue 1: Name is too short
        assertThat(details.get(0).getDefaultMessage())
                .contains("\"name\" must be greater than or equal to 1");
        assertThat(details.get(0).getKey())
                .isEqualTo("container.greaterThanOrEqual");

        // Issue 2: Email is incorrect
