                .contains("\"email\" must be a valid email address");
        assertThat(details.get(1).getKey())
                .isEqualTo("charSequence.email");

        // Issue 3: Age is too high
        assertThat(details.get(2).getDefaultMessage())
                .contains("\"age\" must be less than or equal to 200");
        assertThat(details.get(2).getKey())
                .isEqualTo("numeric.lessThanOrEqual");

        // Issue 4: Account must be enabled
        assertThat(details.get(3).getDefaultMessage())
                .contains("\"enabled\" must be true");
        assertThat(details.get(3).getKey())
                .isEqualTo("boolean.isTrue");
    }
}

